const body = $input.first().json.body || $input.first().json || {};
const THRESHOLD = 75;
const ALGO_ADDRESS_REGEX = /^[A-Z2-7]{58}$/;

if (!body.taskTitle || !body.taskType || !body.receiverAddress) {
  return [{ json: { ok: false, message: 'taskTitle, taskType, and receiverAddress are required.' } }];
}

if (!ALGO_ADDRESS_REGEX.test(String(body.receiverAddress).trim())) {
  return [{ json: { ok: false, message: 'receiverAddress must be a valid Algorand address.' } }];
}

const taskTitle = String(body.taskTitle).trim();
const taskType = String(body.taskType).trim();
const taskBudget = Number(body.taskBudget || 0);
const receiverAddress = String(body.receiverAddress).trim();

return [{
  json: {
    taskTitle,
    taskType,
    taskBudget,
    receiverAddress,
    threshold: THRESHOLD,
    prompt: `You are a professional decision maker for a blockchain task marketplace. Decide whether the submitted task is worth paying for.\n\nReturn STRICT JSON only with these keys:\n- should_pay (boolean)\n- score (number from 0 to 100)\n- reason (string)\n- summary (string)\n\nDecision criteria:\n- Strong reasons to PAY: high business impact, security-sensitive work, measurable delivery, clearly verifiable outcome, direct effect on core product or payment reliability.\n- Strong reasons to DO NOT PAY: vague maintenance work, unclear value, weak ownership, low verifiability, generic cleanup, cosmetic-only tasks, or tasks described too loosely to prove meaningful impact.\n- Tasks like 'fixing errors in console', 'minor cleanup', or similar generic debugging should usually be DO NOT PAY unless the prompt clearly explains a serious user-facing bug, production impact, or a specific verifiable result.\n- If the task description is vague, generic, or lacks a clearly verifiable outcome, you should decide DO NOT PAY and explain that the task is too vague to justify payment.\n\nRules:\n- If should_pay is true, score must be >= ${THRESHOLD}.\n- If should_pay is false, score must be < ${THRESHOLD}.\n- Summary must clearly say PAY or DO NOT PAY.\n- Be decisive and concise.\n\nTask title: ${taskTitle}\nTask type: ${taskType}\nBudget ALGO: ${taskBudget}\nReceiver address: ${receiverAddress}`
  }
}];

const THRESHOLD = 75;
const raw = $input.first().json.text || $input.first().json.response || $input.first().json.output || $input.first().json.message || '{}';

let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch {
  return [{ json: { ok: false, message: 'Model returned invalid JSON. Ensure the OpenAI node returns JSON with at least score and summary.' } }];
}

const score = Number(parsed.score);
if (!Number.isFinite(score)) {
  return [{ json: { ok: false, message: 'Model output is missing a numeric score field.' } }];
}

const normalizedScore = Math.max(0, Math.min(100, score));
const shouldPay = typeof parsed.should_pay === 'boolean'
  ? parsed.should_pay
  : normalizedScore >= THRESHOLD;

if (typeof parsed.should_pay === 'boolean') {
  if (shouldPay === true && normalizedScore < THRESHOLD) {
    return [{ json: { ok: false, message: `Model output is inconsistent: should_pay=true but score=${normalizedScore} is below threshold ${THRESHOLD}.` } }];
  }

  if (shouldPay === false && normalizedScore >= THRESHOLD) {
    return [{ json: { ok: false, message: `Model output is inconsistent: should_pay=false but score=${normalizedScore} meets or exceeds threshold ${THRESHOLD}.` } }];
  }
}

const status = normalizedScore >= THRESHOLD ? 'completed' : 'failed';
const decisionReason = String(parsed.reason || '').trim() || (status === 'completed'
  ? 'The task appears strong enough to justify payment.'
  : 'The task does not appear strong enough to justify payment.');
const summary = String(parsed.summary || '').trim();

if (!summary) {
  return [{ json: { ok: false, message: 'Model output is missing a summary field.' } }];
}

return [{
  json: {
    ok: true,
    analysis: {
      score: normalizedScore,
      status,
      decision: shouldPay ? 'pay' : 'skip',
      verdict: status === 'completed' ? 'Threshold passed' : 'Threshold not met',
      decisionReason,
      summary,
      source: 'n8n-openai'
    }
  }
}];
